        """Test getting value from single level dictionary."""
        data = {"name": "John", "age": 30}
        assert deep_get(data, "name") == "John"
        assert deep_get(data, "age") == 30

    def test_nested_dict_access(self):
        """Test getting value from nested dictionary."""
        data = {
            "user": {
                "profile": {
                    "name": "Alice",
                    "settings": {
                        "theme": "dark"
                    }
                }
            }
        }
        assert deep_get(data, "user.profile.name") == "Alice"
        assert deep_get(data, "user.profile.settings.theme") == "dark"

    def test_deeply_nested_structure(self):
        """Test with deeply nested structure."""
        data = {"a": {"b": {"c": {"d": {"e": "deep_value"}}}}}
        assert deep_get(data, "a.b.c.d.e") == "deep_value"

    def test_various_value_types(self):
        """Test with different value types."""
