                "dict": {"inner": "value"}
            }
        }
        assert deep_get(data, "string") == "text"
        assert deep_get(data, "number") == 42
        assert deep_get(data, "boolean") is True
        assert deep_get(data, "null") is None
        assert deep_get(data, "list") == [1, 2, 3]
        assert deep_get(data, "nested.float") == 3.14
        assert deep_get(data, "nested.dict") == {"inner": "value"}

